import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { writeFileSync, mkdirSync, rmSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import {
  getAllVaults,
  getVaultDir,
  getExpectedHash,
} from '../../src/lib/registry.js';

// Helpers to build a fake ~/.claude.json for each test
function makeCfgPath(dir) {
  return join(dir, '.claude.json');
}

function writeCfg(dir, mcpServers) {
  writeFileSync(makeCfgPath(dir), JSON.stringify({ mcpServers }));
}

function vaultEntry(dir, hash) {
  const entry = {
    command: 'node',
    args: [`${dir}/.mcp-start.js`, hash ? `--expected-sha256=${hash}` : undefined].filter(Boolean),
  };
  return entry;
}

let tmp;
beforeEach(() => {
  tmp = join(tmpdir(), `vk-test-${Date.now()}`);
  mkdirSync(tmp);
});
afterEach(() => {
  rmSync(tmp, { recursive: true, force: true });
});

// ─── getAllVaults ────────────────────────────────────────────────────────────

describe('getAllVaults', () => {
  it('returns empty array when config file does not exist', async () => {
    const result = await getAllVaults(makeCfgPath(tmp));
    expect(result).toEqual([]);
  });

  it('returns empty array when mcpServers is empty', async () => {
    writeCfg(tmp, {});
    const result = await getAllVaults(makeCfgPath(tmp));
    expect(result).toEqual([]);
  });

  it('returns only entries whose args include an .mcp-start.js path', async () => {
    const vaultDir = join(tmp, 'MyVault');
    writeCfg(tmp, {
      MyVault: vaultEntry(vaultDir),
      'other-tool': { command: 'node', args: ['some-other.js'] },
    });
    const result = await getAllVaults(makeCfgPath(tmp));
    expect(result).toHaveLength(1);
    expect(result[0].name).toBe('MyVault');
  });

  it('includes dir and hash on each entry', async () => {
    const vaultDir = join(tmp, 'Notes');
    const hash = 'abc123';
    writeCfg(tmp, { Notes: vaultEntry(vaultDir, hash) });
    const [vault] = await getAllVaults(makeCfgPath(tmp));
    expect(vault.name).toBe('Notes');
    expect(vault.dir).toBe(vaultDir);
    expect(vault.hash).toBe(hash);
  });

  it('sets hash to null when no --expected-sha256 arg present', async () => {
    const vaultDir = join(tmp, 'NoHash');
    writeCfg(tmp, { NoHash: vaultEntry(vaultDir) });
    const [vault] = await getAllVaults(makeCfgPath(tmp));
    expect(vault.hash).toBeNull();
  });

  it('returns vaults sorted alphabetically by name', async () => {
    const dirs = ['Zebra', 'Alpha', 'Mango'].map(n => join(tmp, n));
    writeCfg(tmp, Object.fromEntries(dirs.map((d, i) => (['Zebra', 'Alpha', 'Mango'][i], vaultEntry(d)))));
    const result = await getAllVaults(makeCfgPath(tmp));
    expect(result.map(v => v.name)).toEqual(['Alpha', 'Mango', 'Zebra']);
  });
});

// ─── getVaultDir ────────────────────────────────────────────────────────────

describe('getVaultDir', () => {
  it('returns the vault directory for a registered vault', async () => {
    const vaultDir = join(tmp, 'MyVault');
    writeCfg(tmp, { MyVault: vaultEntry(vaultDir) });
    const result = await getVaultDir('MyVault', makeCfgPath(tmp));
    expect(result).toBe(vaultDir);
  });

  it('returns null when vault is not registered', async () => {
    writeCfg(tmp, {});
    const result = await getVaultDir('NonExistent', makeCfgPath(tmp));
    expect(result).toBeNull();
  });

  it('returns null when config does not exist', async () => {
    const result = await getVaultDir('AnyVault', makeCfgPath(tmp));
    expect(result).toBeNull();
  });
});

// ─── getExpectedHash ────────────────────────────────────────────────────────

describe('getExpectedHash', () => {
  it('returns the pinned hash for a registered vault', async () => {
    const vaultDir = join(tmp, 'MyVault');
    const hash = 'deadbeef';
    writeCfg(tmp, { MyVault: vaultEntry(vaultDir, hash) });
    const result = await getExpectedHash('MyVault', makeCfgPath(tmp));
    expect(result).toBe(hash);
  });

  it('returns null when vault has no pinned hash', async () => {
    const vaultDir = join(tmp, 'MyVault');
    writeCfg(tmp, { MyVault: vaultEntry(vaultDir) });
    const result = await getExpectedHash('MyVault', makeCfgPath(tmp));
    expect(result).toBeNull();
  });

  it('returns null when vault is not registered', async () => {
    writeCfg(tmp, {});
    const result = await getExpectedHash('Ghost', makeCfgPath(tmp));
    expect(result).toBeNull();
  });
});
